+    targets = bench_memcpy_sizes, bench_strlen, bench_memcmp_sizes, bench_strcmp, bench_strchr_absent, bench_strrchr_absent, bench_strcspn_absent, bench_strpbrk_absent, bench_strspn_full, bench_strsep_absent, bench_strchrnul_absent, bench_wcsrchr_absent, bench_wcsstr_absent
 );
